cd /tmp/mermaid-audit && cat > validate.mjs <<'JS'
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

// Use the mermaid package via headless validation by parsing only
const { default: mermaid } = await import('/opt/homebrew/lib/node_modules/@mermaid-js/mermaid-cli/node_modules/mermaid/dist/mermaid.core.mjs').catch(async () => {
  return await import('mermaid');
});

const blocksDir = '/tmp/mermaid-audit/blocks';
const files = fs.readdirSync(blocksDir).filter(f => f.endsWith('.mmd')).sort();
const results = [];
for (const f of files) {
  const src = fs.readFileSync(path.join(blocksDir, f), 'utf8');
  try {
    await mermaid.parse(src);
    results.push({ id: f, ok: true });
  } catch (e) {
    results.push({ id: f, ok: false, err: String(e.message || e).split('\n').slice(0,4).join(' | ') });
  }
}
const ok = results.filter(r => r.ok).length;
const fail = results.filter(r => !r.ok);
console.log(`OK: ${ok} / ${results.length}`);
console.log('---FAILURES---');
for (const r of fail) console.log(`${r.id}: ${r.err}`);
JS
node validate.mjs 2>&1 | tail -200

