cd /tmp/mermaid-audit && cat > validate3.mjs <<'JS'
import fs from 'fs';
import path from 'path';
import { JSDOM } from 'jsdom';

const dom = new JSDOM('<!DOCTYPE html><html><body><div id="container"></div></body></html>', { url: 'http://localhost' });
globalThis.window = dom.window;
globalThis.document = dom.window.document;
globalThis.DOMParser = dom.window.DOMParser;
globalThis.XMLSerializer = dom.window.XMLSerializer;
globalThis.navigator = dom.window.navigator;
globalThis.HTMLElement = dom.window.HTMLElement;
globalThis.Element = dom.window.Element;
globalThis.Node = dom.window.Node;

const mermaid = (await import('mermaid')).default;

const blocksDir = '/tmp/mermaid-audit/blocks';
const indexJson = JSON.parse(fs.readFileSync('/tmp/mermaid-audit/index.json', 'utf8'));
const fileMap = Object.fromEntries(indexJson.map(r => [String(r.id).padStart(3,'0'), r]));
const files = fs.readdirSync(blocksDir).filter(f => f.endsWith('.mmd')).sort();
const results = [];
for (const f of files) {
  const id = f.replace('.mmd','');
  const src = fs.readFileSync(path.join(blocksDir, f), 'utf8');
  try {
    await mermaid.parse(src);
    results.push({ id, ok: true, ...fileMap[id] });
  } catch (e) {
    results.push({ id, ok: false, err: String(e.message || e).split('\n').slice(0,4).join(' / '), ...fileMap[id] });
  }
}
const ok = results.filter(r => r.ok).length;
const fail = results.filter(r => !r.ok);
console.log(`OK: ${ok} / ${results.length}`);
console.log('---FAILURES---');
for (const r of fail) console.log(`${r.id} | ${r.file} | block ${r.block}: ${r.err}`);
JS
